(function () {
  const mocks = [
    {
      id: 'jee-advanced-short-20',
      name: 'JEE Advanced — Short Mock (20 Questions)',
      template: 'nta',
      examCatalogueId: 'jee-advanced',
      kind: 'mock', scope: 'short', sectionTag: null,
      durationMin: 15,
      marking: { correct: 3, wrong: -1, unattempted: 0 },
      allowSectionSwitch: true, timerMode: 'full', calculator: false,
      questionTypes: ['mcq'], languages: ['en'],
      sections: [
        { id: 'phy', name: 'Physics', questions: [
          { id: 'jee-advanced-s20-1', text: 'A solid sphere of mass M and radius R rolls without slipping down an incline. What fraction of its total kinetic energy is rotational?', options: ['2/7', '2/5', '1/2', '5/7'], correct: 0, topic: 'Rotational Dynamics', difficulty: 'medium', explanation: 'For a solid sphere I = (2/5)MR². Rolling: v = ωR. KE_rot = ½Iω² = ½(2/5)MR²(v/R)² = (1/5)Mv². KE_trans = ½Mv². Total = (1/5 + 1/2)Mv² = (7/10)Mv². Fraction rotational = (1/5)/(7/10) = (2/10)/(7/10) = 2/7.' },
          { id: 'jee-advanced-s20-2', text: 'A satellite in a circular orbit of radius r around Earth has speed v. To move it to a circular orbit of radius 4r, the new orbital speed is:', options: ['v/4', 'v/2', '2v', 'v√2'], correct: 1, topic: 'Gravitation', difficulty: 'medium', explanation: 'Orbital speed v = √(GM/r), so v ∝ 1/√r. At radius 4r: v′ = √(GM/4r) = (1/2)√(GM/r) = v/2.' },
          { id: 'jee-advanced-s20-3', text: 'Water flows through a horizontal pipe whose cross-sectional area halves. If the speed in the wider part is 2 m/s, the speed in the narrower part is:', options: ['1 m/s', '2 m/s', '4 m/s', '8 m/s'], correct: 2, topic: 'Fluid Mechanics', difficulty: 'easy', explanation: 'Continuity equation: A₁v₁ = A₂v₂. With A₂ = A₁/2, v₂ = (A₁/A₂)v₁ = 2 × 2 = 4 m/s.' },
          { id: 'jee-advanced-s20-4', text: 'One mole of an ideal monatomic gas undergoes an adiabatic process. If its temperature doubles, the ratio of final to initial volume is:', options: ['2^(3/2)', '2^(-3/2)', '2^(2/3)', '2^(-2/3)'], correct: 1, topic: 'Thermodynamics', difficulty: 'medium-hard', explanation: 'Adiabatic: TV^(γ-1) = const, γ = 5/3 for monatomic, so γ-1 = 2/3. T₁V₁^(2/3) = T₂V₂^(2/3). (V₂/V₁)^(2/3) = T₁/T₂ = 1/2. V₂/V₁ = (1/2)^(3/2) = 2^(-3/2).' },
          { id: 'jee-advanced-s20-5', text: 'A string fixed at both ends vibrates in its third harmonic. The number of nodes (including the ends) is:', options: ['2', '3', '4', '6'], correct: 2, topic: 'Waves', difficulty: 'easy-medium', explanation: 'The n-th harmonic has n antinodes and (n+1) nodes counting the two fixed ends. For n = 3: nodes = 4.' },
          { id: 'jee-advanced-s20-6', text: 'A charged particle enters a uniform magnetic field perpendicular to its velocity. If kinetic energy is quadrupled (charge and mass fixed), the radius of its circular path becomes:', options: ['half', 'unchanged', 'doubled', 'quadrupled'], correct: 2, topic: 'Electromagnetism', difficulty: 'medium', explanation: 'r = mv/(qB) and KE = ½mv², so v = √(2KE/m), giving r ∝ v ∝ √KE. Quadrupling KE multiplies r by √4 = 2, so radius doubles.' },
          { id: 'jee-advanced-s20-7', text: 'In a photoelectric experiment, the stopping potential is 2 V for light of frequency f. If the work function equals hf/2, the stopping potential for light of frequency 2f is:', options: ['3.5 V', '4 V', '6 V', '8 V'], correct: 2, topic: 'Modern Physics', difficulty: 'hard', explanation: 'eV_s = hf − φ. With φ = hf/2: e(2) = hf − hf/2 = hf/2, so hf = 4e (in volt-equivalents, hf/e = 4 V). For 2f: eV_s′ = h(2f) − φ = 2hf − hf/2 = (3/2)hf = (3/2)(4e) = 6e. So V_s′ = 6 V.' },
        ]},
        { id: 'che', name: 'Chemistry', questions: [
          { id: 'jee-advanced-s20-8', text: 'For the equilibrium N₂O₄(g) ⇌ 2NO₂(g), if the volume is doubled at constant temperature, the equilibrium shifts:', options: ['toward N₂O₄', 'toward NO₂', 'no shift', 'reaction stops'], correct: 1, topic: 'Chemical Equilibrium', difficulty: 'easy-medium', explanation: 'Doubling volume lowers pressure. Le Chatelier: the system shifts toward the side with more gas moles. Right side has 2 mol vs 1 mol left, so it shifts toward NO₂.' },
          { id: 'jee-advanced-s20-9', text: 'The pH of a 0.01 M solution of a strong monoprotic acid is:', options: ['1', '2', '3', '12'], correct: 1, topic: 'Ionic Equilibrium', difficulty: 'easy', explanation: 'Strong acid fully dissociates: [H⁺] = 0.01 = 10⁻² M. pH = −log(10⁻²) = 2.' },
          { id: 'jee-advanced-s20-10', text: 'A galvanic cell has a standard EMF of +1.10 V with n = 2. The standard Gibbs free energy change (F = 96500 C/mol) is approximately:', options: ['−106 kJ', '−212 kJ', '−53 kJ', '+212 kJ'], correct: 1, topic: 'Electrochemistry', difficulty: 'medium', explanation: 'ΔG° = −nFE° = −(2)(96500)(1.10) = −212300 J ≈ −212 kJ.' },
          { id: 'jee-advanced-s20-11', text: 'For a first-order reaction, the time required for 75% completion relative to the half-life t½ is:', options: ['t½', '1.5 t½', '2 t½', '3 t½'], correct: 2, topic: 'Chemical Kinetics', difficulty: 'medium', explanation: '75% completion leaves 25% = (½)² of reactant, which corresponds to two half-lives. So time = 2 t½.' },
          { id: 'jee-advanced-s20-12', text: 'The oxidation state of chromium in the dichromate ion Cr₂O₇²⁻ is:', options: ['+3', '+6', '+7', '+2'], correct: 1, topic: 'Coordination & Redox', difficulty: 'easy-medium', explanation: 'Let oxidation state of Cr = x. 2x + 7(−2) = −2. 2x − 14 = −2, 2x = 12, x = +6.' },
          { id: 'jee-advanced-s20-13', text: 'Which reagent gives a deep blue colour with Cu²⁺ ions in qualitative analysis, confirming copper?', options: ['Excess NH₃', 'Dilute HCl', 'NaOH only', 'Dilute H₂SO₄'], correct: 0, topic: 'Qualitative Analysis', difficulty: 'medium', explanation: 'Cu²⁺ with excess aqueous NH₃ forms the deep blue tetraamminecopper(II) complex [Cu(NH₃)₄]²⁺, a confirmatory test for copper.' },
          { id: 'jee-advanced-s20-14', text: 'In an E1 elimination of a tertiary alkyl halide, the rate-determining step involves:', options: ['simultaneous loss of leaving group and proton', 'formation of a carbocation', 'attack by base on carbon', 'backside attack by nucleophile'], correct: 1, topic: 'Organic Mechanisms', difficulty: 'medium-hard', explanation: 'E1 is unimolecular: the slow, rate-determining step is ionisation of the C–leaving group bond to form a carbocation. Proton loss occurs in a fast subsequent step. Rate = k[substrate].' },
        ]},
        { id: 'math', name: 'Mathematics', questions: [
          { id: 'jee-advanced-s20-15', text: 'If z = 1 + i, then z⁴ equals:', options: ['−4', '4', '−4i', '4i'], correct: 0, topic: 'Complex Numbers', difficulty: 'medium', explanation: 'z² = (1+i)² = 1 + 2i + i² = 1 + 2i − 1 = 2i. z⁴ = (z²)² = (2i)² = 4i² = −4.' },
          { id: 'jee-advanced-s20-16', text: 'The value of ∫₀^(π/2) sin²x dx is:', options: ['π/2', 'π/4', '1', 'π'], correct: 1, topic: 'Definite Integrals', difficulty: 'medium', explanation: 'sin²x = (1 − cos2x)/2. ∫₀^(π/2)(1−cos2x)/2 dx = ½[x − (sin2x)/2]₀^(π/2) = ½[(π/2 − 0) − (0 − 0)] = π/4.' },
          { id: 'jee-advanced-s20-17', text: 'The function f(x) = x³ − 3x has a local maximum at:', options: ['x = 1', 'x = −1', 'x = 0', 'x = 3'], correct: 1, topic: 'Calculus', difficulty: 'easy-medium', explanation: "f′(x) = 3x² − 3 = 0 gives x = ±1. f″(x) = 6x. At x = −1, f″ = −6 < 0 → local maximum. At x = 1, f″ = 6 > 0 → local minimum." },
          { id: 'jee-advanced-s20-18', text: 'The eccentricity of the ellipse x²/25 + y²/16 = 1 is:', options: ['3/5', '4/5', '3/4', '5/4'], correct: 0, topic: 'Conics', difficulty: 'medium', explanation: 'a² = 25, b² = 16. e = √(1 − b²/a²) = √(1 − 16/25) = √(9/25) = 3/5.' },
          { id: 'jee-advanced-s20-19', text: 'If a⃗ = i + 2j + 2k and b⃗ = 2i − j, the magnitude of a⃗ × b⃗ is:', options: ['√45', '√44', '7', '√50'], correct: 0, topic: 'Vectors', difficulty: 'medium-hard', explanation: 'a⃗ × b⃗ = |i j k; 1 2 2; 2 −1 0| = i(2·0 − 2·(−1)) − j(1·0 − 2·2) + k(1·(−1) − 2·2) = i(2) − j(−4) + k(−5) = (2, 4, −5). Magnitude = √(4 + 16 + 25) = √45.' },
          { id: 'jee-advanced-s20-20', text: 'Two fair dice are rolled. The probability that the sum is 7 is:', options: ['1/6', '1/9', '5/36', '1/12'], correct: 0, topic: 'Probability', difficulty: 'easy', explanation: 'Sum = 7 from (1,6),(2,5),(3,4),(4,3),(5,2),(6,1) = 6 outcomes out of 36. Probability = 6/36 = 1/6.' },
        ]},
      ],
    },
    {
      id: 'jee-advanced-short-25',
      name: 'JEE Advanced — Short Mock (25 Questions)',
      template: 'nta',
      examCatalogueId: 'jee-advanced',
      kind: 'mock', scope: 'short', sectionTag: null,
      durationMin: 20,
      marking: { correct: 3, wrong: -1, unattempted: 0 },
      allowSectionSwitch: true, timerMode: 'full', calculator: false,
      questionTypes: ['mcq'], languages: ['en'],
      sections: [
        { id: 'phy', name: 'Physics', questions: [
          { id: 'jee-advanced-s25-1', text: 'A uniform rod of length L pivoted at one end is released from the horizontal position. Its angular acceleration at release is:', options: ['g/L', '2g/L', '3g/(2L)', 'g/(2L)'], correct: 2, topic: 'Rotational Dynamics', difficulty: 'medium-hard', explanation: 'Torque about pivot = Mg(L/2). I = ML²/3. α = τ/I = Mg(L/2)/(ML²/3) = (gL/2)(3/L²) = 3g/(2L).' },
          { id: 'jee-advanced-s25-2', text: 'The escape velocity from a planet of radius R and mass M is v_e. If both M and R are doubled, the new escape velocity is:', options: ['v_e', 'v_e/2', '2v_e', 'v_e√2'], correct: 0, topic: 'Gravitation', difficulty: 'medium', explanation: 'v_e = √(2GM/R). Doubling both M and R: v_e′ = √(2G(2M)/(2R)) = √(2GM/R) = v_e. Unchanged.' },
          { id: 'jee-advanced-s25-3', text: 'A cubical block floats in water with 60% of its volume submerged. The density of the block (water = 1000 kg/m³) is:', options: ['400 kg/m³', '600 kg/m³', '1000 kg/m³', '1666 kg/m³'], correct: 1, topic: 'Fluid Mechanics', difficulty: 'easy-medium', explanation: 'Floating: ρ_block·V·g = ρ_water·(0.6V)·g. ρ_block = 0.6 × 1000 = 600 kg/m³.' },
          { id: 'jee-advanced-s25-4', text: 'A Carnot engine operates between a hot reservoir at 400 K and a cold reservoir at 300 K. What is its efficiency?', options: ['20%', '25%', '33%', '75%'], correct: 1, topic: 'Thermodynamics', difficulty: 'easy', explanation: 'Carnot efficiency η = 1 − T_cold/T_hot = 1 − 300/400 = 0.25 = 25%.' },
          { id: 'jee-advanced-s25-5', text: 'A pipe closed at one end resonates at its fundamental frequency 150 Hz. The frequency of its next (second) resonance is:', options: ['300 Hz', '450 Hz', '225 Hz', '600 Hz'], correct: 1, topic: 'Waves', difficulty: 'medium', explanation: 'A closed pipe supports only odd harmonics: f, 3f, 5f, ... Next after fundamental 150 Hz is 3f = 450 Hz.' },
          { id: 'jee-advanced-s25-6', text: 'Two parallel wires carry equal currents in opposite directions. The force between them is:', options: ['attractive', 'repulsive', 'zero', 'perpendicular to wires'], correct: 1, topic: 'Electromagnetism', difficulty: 'easy-medium', explanation: 'Parallel currents in the same direction attract; antiparallel (opposite-direction) currents repel. Hence the force is repulsive.' },
          { id: 'jee-advanced-s25-7', text: 'Light of wavelength 600 nm in vacuum enters a medium of refractive index 1.5. Its wavelength in the medium is:', options: ['400 nm', '600 nm', '900 nm', '300 nm'], correct: 0, topic: 'Optics', difficulty: 'medium', explanation: 'λ_medium = λ_vacuum/n = 600/1.5 = 400 nm. (Frequency stays constant; speed and wavelength decrease.)' },
          { id: 'jee-advanced-s25-8', text: 'A radioactive sample has a half-life of 10 days. The fraction remaining after 30 days is:', options: ['1/2', '1/4', '1/8', '1/16'], correct: 2, topic: 'Modern Physics', difficulty: 'easy', explanation: '30 days = 3 half-lives. Fraction remaining = (1/2)³ = 1/8.' },
          { id: 'jee-advanced-s25-9', text: 'In Young\'s double-slit experiment, the slit separation is doubled and the screen distance is halved. The fringe width becomes:', options: ['1/4 of original', '1/2 of original', 'unchanged', 'doubled'], correct: 0, topic: 'Optics', difficulty: 'medium-hard', explanation: 'Fringe width β = λD/d. New β′ = λ(D/2)/(2d) = λD/(4d) = β/4. So it is one-quarter of the original.' },
        ]},
        { id: 'che', name: 'Chemistry', questions: [
          { id: 'jee-advanced-s25-10', text: 'For the reaction A + B ⇌ C, K_c = 4 at a given temperature. If the reverse reaction is written, its equilibrium constant is:', options: ['4', '1/4', '16', '2'], correct: 1, topic: 'Chemical Equilibrium', difficulty: 'easy-medium', explanation: 'The equilibrium constant of the reverse reaction is the reciprocal: K_reverse = 1/K_forward = 1/4.' },
          { id: 'jee-advanced-s25-11', text: 'The solubility product of AgCl is 1.6 × 10⁻¹⁰. Its molar solubility in pure water is:', options: ['1.6 × 10⁻¹⁰ M', '1.26 × 10⁻⁵ M', '4 × 10⁻⁵ M', '8 × 10⁻⁶ M'], correct: 1, topic: 'Ionic Equilibrium', difficulty: 'medium', explanation: 'AgCl ⇌ Ag⁺ + Cl⁻, Ksp = s². s = √(1.6 × 10⁻¹⁰) = √1.6 × 10⁻⁵ ≈ 1.26 × 10⁻⁵ M.' },
          { id: 'jee-advanced-s25-12', text: 'During electrolysis, the same quantity of charge is passed through molten AlCl₃ and molten NaCl. The mole ratio of Al to Na deposited is:', options: ['1:1', '1:3', '3:1', '1:2'], correct: 1, topic: 'Electrochemistry', difficulty: 'medium-hard', explanation: 'Moles deposited = charge/(n·F). Al³⁺ needs 3 electrons, Na⁺ needs 1. For equal charge Q: n_Al = Q/(3F), n_Na = Q/F. Ratio Al:Na = (1/3):1 = 1:3.' },
          { id: 'jee-advanced-s25-13', text: 'The rate constant of a reaction has units of mol L⁻¹ s⁻¹. The order of the reaction is:', options: ['zero', 'first', 'second', 'third'], correct: 0, topic: 'Chemical Kinetics', difficulty: 'medium', explanation: 'Rate units are mol L⁻¹ s⁻¹. For order n, k has units (mol L⁻¹)^(1−n) s⁻¹. Matching gives 1 − n = 1, so n = 0 (zero order).' },
          { id: 'jee-advanced-s25-14', text: 'The hybridisation of the central atom in [Ni(CN)₄]²⁻ (square planar) is:', options: ['sp³', 'dsp²', 'sp³d', 'd²sp³'], correct: 1, topic: 'Coordination Chemistry', difficulty: 'medium-hard', explanation: 'A square-planar geometry corresponds to dsp² hybridisation. Ni²⁺ with strong-field CN⁻ ligands pairs its d-electrons, freeing a 3d orbital for dsp² hybridisation.' },
          { id: 'jee-advanced-s25-15', text: 'Which cation gives a chrome-yellow precipitate with potassium chromate (K₂CrO₄) solution?', options: ['Pb²⁺', 'Cu²⁺', 'Fe³⁺', 'Zn²⁺'], correct: 0, topic: 'Qualitative Analysis', difficulty: 'medium', explanation: 'Pb²⁺ + CrO₄²⁻ → PbCrO₄↓, a characteristic chrome-yellow precipitate used to confirm lead ions.' },
          { id: 'jee-advanced-s25-16', text: 'In an SN1 solvolysis, the rate increases most when going from a primary to a tertiary substrate because:', options: ['steric hindrance increases', 'the carbocation is more stable', 'the leaving group changes', 'the nucleophile is stronger'], correct: 1, topic: 'Organic Mechanisms', difficulty: 'hard', explanation: 'SN1 rate depends on carbocation stability. Tertiary carbocations are stabilised by hyperconjugation and inductive electron donation from three alkyl groups, lowering the activation energy of the rate-determining ionisation step.' },
          { id: 'jee-advanced-s25-17', text: 'A compound has one chiral centre. The maximum number of stereoisomers it can exhibit is:', options: ['1', '2', '3', '4'], correct: 1, topic: 'Stereochemistry', difficulty: 'easy-medium', explanation: 'Maximum stereoisomers = 2ⁿ where n = number of chiral centres. With n = 1, 2¹ = 2 (a pair of enantiomers).' },
        ]},
        { id: 'math', name: 'Mathematics', questions: [
          { id: 'jee-advanced-s25-18', text: 'The domain of f(x) = √(4 − x²) is:', options: ['[−2, 2]', '(−2, 2)', '[0, 2]', 'all reals'], correct: 0, topic: 'Functions', difficulty: 'easy', explanation: 'Require 4 − x² ≥ 0 → x² ≤ 4 → −2 ≤ x ≤ 2. Domain = [−2, 2].' },
          { id: 'jee-advanced-s25-19', text: 'The modulus of the complex number (3 + 4i)/(1 − i) is:', options: ['5/√2', '5', '√2', '5√2'], correct: 0, topic: 'Complex Numbers', difficulty: 'medium', explanation: '|z₁/z₂| = |z₁|/|z₂|. |3+4i| = √(9+16) = 5. |1−i| = √2. Modulus = 5/√2.' },
          { id: 'jee-advanced-s25-20', text: 'lim(x→0) (sin3x)/(5x) equals:', options: ['3/5', '1', '5/3', '0'], correct: 0, topic: 'Calculus', difficulty: 'easy-medium', explanation: '(sin3x)/(5x) = (sin3x)/(3x) · (3/5). As x→0, (sin3x)/(3x) → 1, so the limit = 1 × 3/5 = 3/5.' },
          { id: 'jee-advanced-s25-21', text: 'The value of ∫₁^e (1/x) dx is:', options: ['e', '1', 'e − 1', 'ln(e−1)'], correct: 1, topic: 'Definite Integrals', difficulty: 'easy-medium', explanation: '∫(1/x)dx = ln|x|. Evaluated from 1 to e: ln(e) − ln(1) = 1 − 0 = 1.' },
          { id: 'jee-advanced-s25-22', text: 'The shortest distance from the point (1, 2, 2) to the plane 2x + y + 2z + 3 = 0 is:', options: ['3', '11/3', '13/3', '4'], correct: 2, topic: '3D Geometry', difficulty: 'medium', explanation: 'Distance = |2(1)+1(2)+2(2)+3|/√(2²+1²+2²) = |2+2+4+3|/√9 = 11/3.' },
          { id: 'jee-advanced-s25-23', text: 'If a⃗ and b⃗ are unit vectors with a⃗ · b⃗ = 1/2, the angle between them is:', options: ['30°', '45°', '60°', '90°'], correct: 2, topic: 'Vectors', difficulty: 'easy-medium', explanation: 'a⃗ · b⃗ = |a⃗||b⃗|cosθ = (1)(1)cosθ = 1/2. cosθ = 1/2 → θ = 60°.' },
          { id: 'jee-advanced-s25-24', text: 'The number of ways to arrange the letters of the word "LEVEL" is:', options: ['120', '60', '30', '20'], correct: 2, topic: 'Combinatorics', difficulty: 'medium', explanation: 'LEVEL has 5 letters with L repeated twice and E repeated twice. Arrangements = 5!/(2!·2!) = 120/4 = 30.' },
          { id: 'jee-advanced-s25-25', text: 'A bag has 3 red and 2 green balls. Two balls are drawn without replacement. The probability both are red is:', options: ['3/10', '9/25', '3/5', '6/20'], correct: 0, topic: 'Probability', difficulty: 'medium-hard', explanation: 'P(both red) = (3/5)(2/4) = 6/20 = 3/10. Equivalently C(3,2)/C(5,2) = 3/10.' },
        ]},
      ],
    },
  ];
  window.EXAMS = (window.EXAMS || []).concat(mocks);
})();
